using ArchStudy.Hexagonal.Domain;
using ArchStudy.Hexagonal.Ports.Driven;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Hexagonal.Adapters.Driven.Persistence;

public class EfAccountStore(HexagonalDbContext db) : IAccountStore
{
    public Task<Account?> LoadAsync(Guid id, CancellationToken ct) =>
        db.Accounts.FirstOrDefaultAsync(a => a.Id == id, ct);

    public async Task SaveAsync(Account account, CancellationToken ct)
    {
        var entry = db.Entry(account);
        if (entry.State == EntityState.Detached)
        {
            await db.Accounts.AddAsync(account, ct);
        }
    }
}

public class EfTransactionStore(HexagonalDbContext db) : ITransactionStore
{
    public async Task<IReadOnlyList<Transaction>> ListByAccountAsync(Guid accountId, CancellationToken ct) =>
        await db.Transactions
            .Where(t => t.AccountId == accountId)
            .OrderByDescending(t => t.Timestamp)
            .ToListAsync(ct);

    public async Task RecordAsync(Transaction transaction, CancellationToken ct) =>
        await db.Transactions.AddAsync(transaction, ct);
}

public class EfTransactionalScope(HexagonalDbContext db) : ITransactionalScope
{
    public Task CommitAsync(CancellationToken ct) => db.SaveChangesAsync(ct);
}

using ArchStudy.Hexagonal.Domain;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Hexagonal.Adapters.Driven.Persistence;

public class HexagonalDbContext(DbContextOptions<HexagonalDbContext> options) : DbContext(options)
{
    public DbSet<Account> Accounts => Set<Account>();
    public DbSet<Transaction> Transactions => Set<Transaction>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Account>(b =>
        {
            b.HasKey(a => a.Id);
            b.Property(a => a.Owner).IsRequired();
        });

        modelBuilder.Entity<Transaction>(b => b.HasKey(t => t.Id));
    }
}

using ArchStudy.Hexagonal.Ports.Driving;
using ArchStudy.Shared.Dtos;

namespace ArchStudy.Hexagonal.Adapters.Driving.Http;

public static class HexagonalEndpoints
{
    public static void Map(RouteGroupBuilder group)
    {
        group.MapPost("/accounts", async Task<IResult> (CreateAccountRequest req, IAccountUseCases useCases, CancellationToken ct) =>
        {
            var account = await useCases.OpenAccountAsync(req.Owner, ct);
            return Results.Created($"/hexagonal/accounts/{account.Id}", account);
        });

        group.MapGet("/accounts/{id:guid}", async Task<IResult> (Guid id, IAccountUseCases useCases, CancellationToken ct) =>
        {
            var account = await useCases.GetAccountAsync(id, ct);
            return account is null ? Results.NotFound() : Results.Ok(account);
        });

        group.MapGet("/accounts/{id:guid}/transactions", async Task<IResult> (Guid id, IAccountUseCases useCases, CancellationToken ct) =>
            Results.Ok(await useCases.GetStatementAsync(id, ct)));

        group.MapPost("/accounts/{id:guid}/deposits", async Task<IResult> (Guid id, DepositRequest req, IAccountUseCases useCases, CancellationToken ct) =>
            Results.Ok(await useCases.DepositAsync(id, req.Amount, ct)));

        group.MapPost("/accounts/{id:guid}/withdrawals", async Task<IResult> (Guid id, WithdrawalRequest req, IAccountUseCases useCases, CancellationToken ct) =>
            Results.Ok(await useCases.WithdrawAsync(id, req.Amount, ct)));

        group.MapPost("/transfers", async Task<IResult> (TransferRequest req, ITransferUseCase useCase, CancellationToken ct) =>
        {
            await useCase.TransferAsync(req.FromAccountId, req.ToAccountId, req.Amount, ct);
            return Results.NoContent();
        });
    }
}

using ArchStudy.Hexagonal.Domain;
using ArchStudy.Hexagonal.Ports.Driven;
using ArchStudy.Hexagonal.Ports.Driving;
using ArchStudy.Shared.Dtos;

namespace ArchStudy.Hexagonal.Application;

public class AccountUseCases(
    IAccountStore accountStore,
    ITransactionStore transactionStore,
    ITransactionalScope scope) : IAccountUseCases
{
    public async Task<AccountResponse> OpenAccountAsync(string owner, CancellationToken ct)
    {
        if (string.IsNullOrWhiteSpace(owner)) throw new ArgumentException("Owner required");
        var account = Account.Open(owner);
        await accountStore.SaveAsync(account, ct);
        await scope.CommitAsync(ct);
        return Map(account);
    }

    public async Task<AccountResponse?> GetAccountAsync(Guid id, CancellationToken ct) =>
        (await accountStore.LoadAsync(id, ct)) is { } a ? Map(a) : null;

    public async Task<IReadOnlyList<TransactionResponse>> GetStatementAsync(Guid accountId, CancellationToken ct)
    {
        var rows = await transactionStore.ListByAccountAsync(accountId, ct);
        return rows.Select(t => new TransactionResponse(t.Id, t.AccountId, t.Type, t.Amount, t.Timestamp, t.RelatedAccountId)).ToList();
    }

    public async Task<AccountResponse> DepositAsync(Guid accountId, decimal amount, CancellationToken ct)
    {
        var account = await accountStore.LoadAsync(accountId, ct) ?? throw new KeyNotFoundException("Account not found");
        account.Credit(amount);
        await transactionStore.RecordAsync(Transaction.Record(account.Id, TransactionType.Deposit, amount), ct);
        await scope.CommitAsync(ct);
        return Map(account);
    }

    public async Task<AccountResponse> WithdrawAsync(Guid accountId, decimal amount, CancellationToken ct)
    {
        var account = await accountStore.LoadAsync(accountId, ct) ?? throw new KeyNotFoundException("Account not found");
        account.Debit(amount);
        await transactionStore.RecordAsync(Transaction.Record(account.Id, TransactionType.Withdrawal, amount), ct);
        await scope.CommitAsync(ct);
        return Map(account);
    }

    private static AccountResponse Map(Account a) => new(a.Id, a.Owner, a.Balance, a.CreatedAt);
}

public class TransferUseCase(
    IAccountStore accountStore,
    ITransactionStore transactionStore,
    ITransactionalScope scope) : ITransferUseCase
{
    public async Task TransferAsync(Guid fromId, Guid toId, decimal amount, CancellationToken ct)
    {
        if (fromId == toId) throw new ArgumentException("Accounts must differ");
        var from = await accountStore.LoadAsync(fromId, ct) ?? throw new KeyNotFoundException("Source account not found");
        var to = await accountStore.LoadAsync(toId, ct) ?? throw new KeyNotFoundException("Destination account not found");

        from.Debit(amount);
        to.Credit(amount);

        await transactionStore.RecordAsync(Transaction.Record(from.Id, TransactionType.TransferOut, amount, to.Id), ct);
        await transactionStore.RecordAsync(Transaction.Record(to.Id, TransactionType.TransferIn, amount, from.Id), ct);
        await scope.CommitAsync(ct);
    }
}

namespace ArchStudy.Hexagonal.Domain;

public class Account
{
    public Guid Id { get; private set; }
    public string Owner { get; private set; } = string.Empty;
    public decimal Balance { get; private set; }
    public DateTime CreatedAt { get; private set; }

    private Account() { }

    public static Account Open(string owner) =>
        new()
        {
            Id = Guid.NewGuid(),
            Owner = owner,
            Balance = 0m,
            CreatedAt = DateTime.UtcNow,
        };

    public void Credit(decimal amount)
    {
        if (amount <= 0) throw new ArgumentException("Amount must be positive");
        Balance += amount;
    }

    public void Debit(decimal amount)
    {
        if (amount <= 0) throw new ArgumentException("Amount must be positive");
        if (Balance < amount) throw new InvalidOperationException("Insufficient funds");
        Balance -= amount;
    }
}

using ArchStudy.Shared.Dtos;

namespace ArchStudy.Hexagonal.Domain;

public class Transaction
{
    public Guid Id { get; private set; }
    public Guid AccountId { get; private set; }
    public TransactionType Type { get; private set; }
    public decimal Amount { get; private set; }
    public DateTime Timestamp { get; private set; }
    public Guid? RelatedAccountId { get; private set; }

    private Transaction() { }

    public static Transaction Record(Guid accountId, TransactionType type, decimal amount, Guid? related = null) =>
        new()
        {
            Id = Guid.NewGuid(),
            AccountId = accountId,
            Type = type,
            Amount = amount,
            Timestamp = DateTime.UtcNow,
            RelatedAccountId = related,
        };
}

using ArchStudy.Hexagonal.Adapters.Driven.Persistence;
using ArchStudy.Hexagonal.Adapters.Driving.Http;
using ArchStudy.Hexagonal.Application;
using ArchStudy.Hexagonal.Ports.Driven;
using ArchStudy.Hexagonal.Ports.Driving;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Hexagonal;

public static class HexagonalModule
{
    public static IServiceCollection AddHexagonalModule(this IServiceCollection services)
    {
        services.AddDbContext<HexagonalDbContext>(o => o.UseSqlite("Data Source=archstudy-hexagonal.db"));

        services.AddScoped<IAccountStore, EfAccountStore>();
        services.AddScoped<ITransactionStore, EfTransactionStore>();
        services.AddScoped<ITransactionalScope, EfTransactionalScope>();

        services.AddScoped<IAccountUseCases, AccountUseCases>();
        services.AddScoped<ITransferUseCase, TransferUseCase>();
        return services;
    }

    public static IEndpointRouteBuilder MapHexagonalModule(this IEndpointRouteBuilder routes)
    {
        var group = routes.MapGroup("/hexagonal").WithTags("Hexagonal");
        HexagonalEndpoints.Map(group);
        return routes;
    }

    public static async Task EnsureDatabaseCreatedAsync(IServiceProvider services)
    {
        var db = services.GetRequiredService<HexagonalDbContext>();
        await db.Database.EnsureCreatedAsync();
    }
}

